def find_root(start: Path) -> Path:
    current = start.resolve()
    for candidate in [current] + list(current.parents):
        if (candidate / "package.json").exists() and (candidate / "src/app/features/bkp").exists():
            return candidate
    raise SystemExit("No encuentro la raíz de klaxmap. Ejecuta el script desde el repo.")

def main() -> None:
    parser = argparse.ArgumentParser(description="Parche UX Workbench BKP para klaxmap")
    parser.add_argument("--dry-run", action="store_true", help="Muestra archivos a escribir sin modificar.")
    args = parser.parse_args()

    root = find_root(Path.cwd())
    backup_dir = root / ".bkp_ux_workbench_patch_backups" / datetime.now().strftime("%Y%m%d_%H%M%S")

    print(f"[INFO] Repo: {root}")
    print(f"[INFO] Archivos: {len(FILES)}")

    if args.dry_run:
        for rel in FILES:
            print(f"[DRY] {rel}")
        return

    backup_dir.mkdir(parents=True, exist_ok=True)

    for rel, content in FILES.items():
        target = root / rel
        target.parent.mkdir(parents=True, exist_ok=True)

        if target.exists():
            backup = backup_dir / rel
            backup.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(target, backup)

        target.write_text(content, encoding="utf-8")
        print(f"[OK] {rel}")

    print(f"[OK] Backup creado en: {backup_dir}")
    print("[OK] Ahora ejecuta: npm run build")

if __name__ == "__main__":
    main()
